import{_ as a}from"./chunks/文件受限图.DsG20F9s.js";import{_ as t,o as d,c as i,a2 as l}from"./chunks/framework.DnrXFDHb.js";const b=JSON.parse('{"title":"Модерація зображень і режим доступу","description":"","frontmatter":{},"headers":[],"relativePath":"uk-UA/Safety/image-moderation-and-access-mode.md","filePath":"uk-UA/Safety/image-moderation-and-access-mode.md","lastUpdated":1781962217000}'),o={name:"uk-UA/Safety/image-moderation-and-access-mode.md"};function r(n,e,s,m,p,h){return d(),i("div",null,[...e[0]||(e[0]=[l('<h1 id="модерація-зображень-і-режим-доступу" tabindex="-1">Модерація зображень і режим доступу <a class="header-anchor" href="#модерація-зображень-і-режим-доступу" aria-label="Permalink to &quot;Модерація зображень і режим доступу&quot;">​</a></h1><p>Модерація зображень присвоює завантаженим файлам вікові рейтинги. Режим доступу визначає, які рейтинги можна показувати через публічний доступ.</p><p>Це впливає на публічну галерею, публічні URL файлів і random image API. На адмін-панель обмеження не поширюються: адміністратори все одно можуть переглядати й керувати всіма файлами.</p><h2 id="де-це-налаштовується" tabindex="-1">Де це налаштовується <a class="header-anchor" href="#де-це-налаштовується" aria-label="Permalink to &quot;Де це налаштовується&quot;">​</a></h2><p>Відкрийте адмін-панель і перейдіть до:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Security Settings -&gt; Upload Management -&gt; Image Moderation</span></span></code></pre></div><p>Основні налаштування:</p><ul><li>Access mode</li><li>Enable moderation</li><li>Moderation provider</li></ul><h2 id="що-робить-access-mode" tabindex="-1">Що робить Access Mode <a class="header-anchor" href="#що-робить-access-mode" aria-label="Permalink to &quot;Що робить Access Mode&quot;">​</a></h2><p>Access mode визначає, які вікові рейтинги можуть бути видимі публічно.</p><p>Поточні режими:</p><table tabindex="0"><thead><tr><th>Access Mode</th><th>Рейтинги, видимі публічно</th></tr></thead><tbody><tr><td>Adult mode</td><td>General, R12, R16, R18</td></tr><tr><td>Youth mode</td><td>General, R12, R16</td></tr><tr><td>Teen mode</td><td>General, R12</td></tr><tr><td>Child mode</td><td>Тільки General</td></tr></tbody></table><p>Типово використовується Adult mode.</p><p>Для приватних сайтів або сайтів із дорослим контентом Adult mode може бути доречним. Для більш обережної публічної галереї виберіть Youth, Teen або Child mode.</p><h2 id="що-дає-ввімкнення-модераціі" tabindex="-1">Що дає ввімкнення модерації <a class="header-anchor" href="#що-дає-ввімкнення-модераціі" aria-label="Permalink to &quot;Що дає ввімкнення модерації&quot;">​</a></h2><p>Коли модерація ввімкнена, ImgBed під час завантаження викликає вибраного moderation provider і зберігає визначений віковий рейтинг.</p><p>Основні рейтинги:</p><table tabindex="0"><thead><tr><th>Рейтинг</th><th>Значення</th></tr></thead><tbody><tr><td>General</td><td>Безпечний публічний контент</td></tr><tr><td>R12</td><td>Помірно чутливий контент</td></tr><tr><td>R16</td><td>Більш чутливий контент</td></tr><tr><td>R18</td><td>Контент для дорослих</td></tr></tbody></table><p>Результат модерації використовується під час визначення публічного доступу.</p><p>Якщо модерацію не ввімкнено або старі файли не мають рейтингу, такі файли вважаються unrated. Unrated-файли не прибираються автоматично з публічної галереї або random image API лише через відсутність рейтингу.</p><h2 id="вибір-moderation-provider" tabindex="-1">Вибір moderation provider <a class="header-anchor" href="#вибір-moderation-provider" aria-label="Permalink to &quot;Вибір moderation provider&quot;">​</a></h2><p>Доступні провайдери:</p><ul><li>moderatecontent.com</li><li>nsfwjs</li><li>Sightengine</li></ul><p>У кожного провайдера свої вимоги:</p><ul><li>moderatecontent.com зазвичай потребує API Key.</li><li>nsfwjs зазвичай потребує API endpoint URL.</li><li>Sightengine потребує API user і API secret.</li></ul><p>Вибирайте за своїм акаунтом, доступністю й якістю розпізнавання. Якщо модерацію ввімкнено й налаштовано правильно, ImgBed намагається записати рейтинг зображення під час завантаження.</p><h2 id="вплив-на-публічну-галерею" tabindex="-1">Вплив на публічну галерею <a class="header-anchor" href="#вплив-на-публічну-галерею" aria-label="Permalink to &quot;Вплив на публічну галерею&quot;">​</a></h2><p>Публічна галерея фільтрує файли відповідно до access mode.</p><p>Приклади:</p><ul><li>Adult mode: R18-зображення можуть з&#39;являтися.</li><li>Youth mode: R18-зображення приховані.</li><li>Teen mode: R16 і R18 приховані.</li><li>Child mode: показуються тільки General-зображення.</li></ul><p>Це впливає лише на звичайний публічний доступ. Адмін-панель і далі показує всі файли.</p><h2 id="вплив-на-публічні-url-фаилів" tabindex="-1">Вплив на публічні URL файлів <a class="header-anchor" href="#вплив-на-публічні-url-фаилів" aria-label="Permalink to &quot;Вплив на публічні URL файлів&quot;">​</a></h2><p>Публічні URL файлів — це прямі посилання на зображення, які відкривають відвідувачі.</p><p>Якщо рейтинг файлу дозволений поточним access mode, ImgBed повертає оригінальне зображення.</p><p>Якщо рейтинг вищий за дозволений рівень, звичайний публічний доступ не повертає оригінальне зображення. Натомість ImgBed повертає налаштований blocked result або зображення-заглушку.</p><p>Приклад:</p><ul><li>Поточний режим — Child mode.</li><li>Зображення має рейтинг R18.</li><li>Відвідувач відкриває публічний URL напряму.</li><li>ImgBed не повертає цьому відвідувачу оригінальне R18-зображення.</li></ul><p><img src="'+a+'" alt="Обмежене зображення файлу" loading="lazy"></p><p>Адміністратори, які переглядають файли в адмін-панелі, цим обмеженням не зачіпаються.</p><h2 id="вплив-на-random-image-api" tabindex="-1">Вплив на Random Image API <a class="header-anchor" href="#вплив-на-random-image-api" aria-label="Permalink to &quot;Вплив на Random Image API&quot;">​</a></h2><p>Random image API також фільтрує пул кандидатів за access mode.</p><p>У Child mode випадкові зображення вибираються тільки з файлів із рейтингом General.</p><p>У Youth mode випадкові зображення можуть надходити з General, R12 і R16, але не з R18.</p><p>Так random image API не обходить обмеження публічної галереї.</p><h2 id="зв-язок-із-правилами-списків" tabindex="-1">Зв&#39;язок із правилами списків <a class="header-anchor" href="#зв-язок-із-правилами-списків" aria-label="Permalink to &quot;Зв&#39;язок із правилами списків&quot;">​</a></h2><p>Access mode — не єдине правило публічного доступу. Він працює разом із allow/block list rules.</p><p>Простіше кажучи:</p><ul><li>allowlisted-контент спершу вважається публічним;</li><li>blocklisted-контент не може переглядатися напряму звичайними відвідувачами;</li><li>контент, який не входить до жодного списку, потім перевіряється за access mode.</li></ul><p>Якщо зображення обмежене і віковим рейтингом, і правилами списків, звичайні відвідувачі все одно не зможуть напряму побачити оригінальний файл.</p><h2 id="рекомендовані-налаштування" tabindex="-1">Рекомендовані налаштування <a class="header-anchor" href="#рекомендовані-налаштування" aria-label="Permalink to &quot;Рекомендовані налаштування&quot;">​</a></h2><p>Для публічних сайтів:</p><ul><li>Увімкніть модерацію.</li><li>Виберіть access mode відповідно до аудиторії сайту.</li><li>Для відвідувачів будь-якого віку використовуйте Child mode або Teen mode.</li><li>Уникайте Adult mode, якщо не хочете показувати дорослий контент публічно.</li><li>Переглядайте рейтинги файлів в адмін-панелі й за потреби змінюйте їх вручну.</li></ul><p>Для приватних або особистих сайтів:</p><ul><li>Adult mode зазвичай підходить.</li><li>Увімкніть модерацію, якщо вона корисна.</li><li>Переглядайте й коригуйте рейтинги в адмін-панелі за потреби.</li></ul><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><h3 id="чи-зникнуть-фаили-з-адмін-панелі-після-зміни-access-mode" tabindex="-1">Чи зникнуть файли з адмін-панелі після зміни Access Mode? <a class="header-anchor" href="#чи-зникнуть-фаили-з-адмін-панелі-після-зміни-access-mode" aria-label="Permalink to &quot;Чи зникнуть файли з адмін-панелі після зміни Access Mode?&quot;">​</a></h3><p>Ні.</p><p>Access mode впливає лише на звичайний публічний доступ. На адмін-панель він не впливає.</p><h3 id="чому-після-переходу-на-child-mode-у-публічніи-галереі-стало-менше-зображень" tabindex="-1">Чому після переходу на Child Mode у публічній галереї стало менше зображень? <a class="header-anchor" href="#чому-після-переходу-на-child-mode-у-публічніи-галереі-стало-менше-зображень" aria-label="Permalink to &quot;Чому після переходу на Child Mode у публічній галереї стало менше зображень?&quot;">​</a></h3><p>Child mode дозволяє публічно показувати тільки файли з рейтингом General. R12, R16 і R18 відфільтровуються.</p><h3 id="чи-можуть-публічні-url-відкривати-adult-images" tabindex="-1">Чи можуть публічні URL відкривати adult images? <a class="header-anchor" href="#чи-можуть-публічні-url-відкривати-adult-images" aria-label="Permalink to &quot;Чи можуть публічні URL відкривати adult images?&quot;">​</a></h3><p>Якщо поточний access mode не дозволяє цей рейтинг, звичайні публічні URL не повертають оригінальне зображення.</p><h3 id="чи-може-random-image-api-повернути-обмежені-зображення" tabindex="-1">Чи може Random Image API повернути обмежені зображення? <a class="header-anchor" href="#чи-може-random-image-api-повернути-обмежені-зображення" aria-label="Permalink to &quot;Чи може Random Image API повернути обмежені зображення?&quot;">​</a></h3><p>Ні.</p><p>Random image API фільтрує кандидатів відповідно до поточного access mode.</p><h3 id="що-буде-зі-старими-unrated-images" tabindex="-1">Що буде зі старими unrated images? <a class="header-anchor" href="#що-буде-зі-старими-unrated-images" aria-label="Permalink to &quot;Що буде зі старими unrated images?&quot;">​</a></h3><p>Unrated-зображення не приховуються автоматично лише через відсутність результатів модерації. Їхні рейтинги можна пізніше змінити в адмін-панелі.</p>',67)])])}const g=t(o,[["render",r]]);export{b as __pageData,g as default};
